/**
 * Email notification adapter — delivers notifications via email.
 *
 * Implements NotificationAdapter interface with:
 * - Template rendering: HTML email bodies based on notification type
 * - Recipient resolution: validates and normalizes email addresses
 * - Send method: formats and delivers (or stores for testing) email messages
 *
 * In production, the transport layer would integrate with SMTP or an email API
 * (e.g., SendGrid, AWS SES, Postmark). The current transport stores emails
 * in-memory, suitable for testing and development.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailConfig {
  from: string;
  replyTo?: string;
  appName?: string;
  baseUrl?: string;
}

const defaultEmailConfig: EmailConfig = {
  from: 'noreply@taskflowpro.com',
  appName: 'TaskFlow Pro',
  baseUrl: 'https://taskflowpro.com',
};

/**
 * Represents a fully rendered email ready for delivery.
 */
export interface RenderedEmail {
  from: string;
  replyTo?: string;
  to: string;
  subject: string;
  html: string;
  text: string;
  metadata: Record<string, unknown>;
}

/**
 * Email transport interface — abstracts the actual sending mechanism.
 * Swap this out for SMTP, SendGrid, SES, etc. in production.
 */
export interface EmailTransport {
  sendMail(email: RenderedEmail): Promise<{ messageId: string }>;
}

/**
 * In-memory email transport for testing and development.
 */
export class InMemoryTransport implements EmailTransport {
  private sent: RenderedEmail[] = [];

  async sendMail(email: RenderedEmail): Promise<{ messageId: string }> {
    this.sent.push(email);
    const messageId = `msg-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
    return { messageId };
  }

  getSentEmails(): RenderedEmail[] {
    return [...this.sent];
  }

  clearSentEmails(): void {
    this.sent = [];
  }
}

// --- Template rendering ---

type TemplateData = Record<string, unknown>;

interface EmailTemplate {
  subject: string;
  html: string;
  text: string;
}

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

function renderOrderConfirmation(data: TemplateData, config: EmailConfig): EmailTemplate {
  const orderId = String(data.orderId ?? '');
  const subject = `Order Confirmation: ${orderId}`;

  const text = String(data.body ?? '');

  const html = `<!DOCTYPE html>
<html>
<head><meta charset="utf-8"></head>
<body style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
  <div style="background: #4A90D9; color: white; padding: 20px; text-align: center;">
    <h1>${escapeHtml(config.appName ?? 'TaskFlow Pro')}</h1>
  </div>
  <div style="padding: 20px;">
    <h2>Order Confirmed</h2>
    <p>Thank you for your order <strong>${escapeHtml(orderId)}</strong>.</p>
    <p>${escapeHtml(text)}</p>
    <hr style="border: none; border-top: 1px solid #eee; margin: 20px 0;">
    <p style="color: #888; font-size: 12px;">
      This email was sent by ${escapeHtml(config.appName ?? 'TaskFlow Pro')}.
      If you have questions, please contact support.
    </p>
  </div>
</body>
</html>`;

  return { subject, html, text };
}

function renderOrderStatusUpdate(data: TemplateData, config: EmailConfig): EmailTemplate {
  const orderId = String(data.orderId ?? '');
  const previousStatus = String(data.previousStatus ?? '');
  const newStatus = String(data.newStatus ?? '');
  const subject = `Order Update: ${orderId}`;

  const text = `Your order ${orderId} status has changed from ${previousStatus} to ${newStatus}.`;

  const statusColor = newStatus === 'shipped' ? '#27AE60'
    : newStatus === 'delivered' ? '#2ECC71'
    : newStatus === 'cancelled' ? '#E74C3C'
    : '#F39C12';

  const html = `<!DOCTYPE html>
<html>
<head><meta charset="utf-8"></head>
<body style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
  <div style="background: #4A90D9; color: white; padding: 20px; text-align: center;">
    <h1>${escapeHtml(config.appName ?? 'TaskFlow Pro')}</h1>
  </div>
  <div style="padding: 20px;">
    <h2>Order Status Update</h2>
    <p>Your order <strong>${escapeHtml(orderId)}</strong> has been updated.</p>
    <div style="background: #f9f9f9; padding: 15px; border-radius: 5px; margin: 15px 0;">
      <p style="margin: 5px 0;">Previous status: <strong>${escapeHtml(previousStatus)}</strong></p>
      <p style="margin: 5px 0;">New status: <span style="color: ${statusColor}; font-weight: bold;">${escapeHtml(newStatus)}</span></p>
    </div>
    <hr style="border: none; border-top: 1px solid #eee; margin: 20px 0;">
    <p style="color: #888; font-size: 12px;">
      This email was sent by ${escapeHtml(config.appName ?? 'TaskFlow Pro')}.
    </p>
  </div>
</body>
</html>`;

  return { subject, html, text };
}

function renderUserWelcome(data: TemplateData, config: EmailConfig): EmailTemplate {
  const userId = String(data.userId ?? '');
  const subject = 'Welcome to TaskFlow Pro!';

  const text = String(data.body ?? `Welcome to ${config.appName ?? 'TaskFlow Pro'}! Your account has been created.`);

  const html = `<!DOCTYPE html>
<html>
<head><meta charset="utf-8"></head>
<body style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
  <div style="background: #4A90D9; color: white; padding: 20px; text-align: center;">
    <h1>Welcome to ${escapeHtml(config.appName ?? 'TaskFlow Pro')}!</h1>
  </div>
  <div style="padding: 20px;">
    <h2>Your Account is Ready</h2>
    <p>${escapeHtml(text)}</p>
    <div style="text-align: center; margin: 30px 0;">
      <a href="${escapeHtml(config.baseUrl ?? '#')}/dashboard"
         style="background: #4A90D9; color: white; padding: 12px 30px; text-decoration: none; border-radius: 5px;">
        Get Started
      </a>
    </div>
    <hr style="border: none; border-top: 1px solid #eee; margin: 20px 0;">
    <p style="color: #888; font-size: 12px;">
      This email was sent by ${escapeHtml(config.appName ?? 'TaskFlow Pro')}.
    </p>
  </div>
</body>
</html>`;

  return { subject, html, text };
}

function renderGenericNotification(payload: NotificationPayload, config: EmailConfig): EmailTemplate {
  const html = `<!DOCTYPE html>
<html>
<head><meta charset="utf-8"></head>
<body style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
  <div style="background: #4A90D9; color: white; padding: 20px; text-align: center;">
    <h1>${escapeHtml(config.appName ?? 'TaskFlow Pro')}</h1>
  </div>
  <div style="padding: 20px;">
    <h2>${escapeHtml(payload.subject)}</h2>
    <p>${escapeHtml(payload.body)}</p>
    <hr style="border: none; border-top: 1px solid #eee; margin: 20px 0;">
    <p style="color: #888; font-size: 12px;">
      This email was sent by ${escapeHtml(config.appName ?? 'TaskFlow Pro')}.
    </p>
  </div>
</body>
</html>`;

  return { subject: payload.subject, html, text: payload.body };
}

/**
 * Render an email template based on notification type and metadata.
 */
function renderTemplate(payload: NotificationPayload, config: EmailConfig): EmailTemplate {
  const data: TemplateData = { ...payload.metadata, body: payload.body };

  switch (payload.type) {
    case 'order_confirmation':
      return renderOrderConfirmation(data, config);
    case 'order_status_update':
      return renderOrderStatusUpdate(data, config);
    case 'user_welcome':
      return renderUserWelcome(data, config);
    default:
      return renderGenericNotification(payload, config);
  }
}

// --- Recipient resolution ---

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate and normalize an email recipient address.
 * Returns the normalized address or null if invalid.
 */
export function resolveRecipient(recipient: string): string | null {
  const trimmed = recipient.trim().toLowerCase();
  if (!EMAIL_REGEX.test(trimmed)) {
    return null;
  }
  return trimmed;
}

// --- Adapter implementation ---

export class EmailAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private transport: EmailTransport;
  private config: EmailConfig;

  // Backward-compatible: stores raw payloads for existing tests
  private sentEmails: NotificationPayload[] = [];

  constructor(config: EmailConfig = defaultEmailConfig, transport?: EmailTransport) {
    this.config = { ...defaultEmailConfig, ...config };
    this.transport = transport ?? new InMemoryTransport();
  }

  /**
   * Send an email notification.
   *
   * 1. Resolves and validates the recipient address
   * 2. Renders the email template based on notification type
   * 3. Delivers via the configured transport
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(
      `Sending email to ${payload.recipient}: ${payload.subject}`,
    );

    try {
      // 1. Resolve recipient
      const resolvedRecipient = resolveRecipient(payload.recipient);
      if (!resolvedRecipient) {
        this.logger.error(`Invalid recipient email: ${payload.recipient}`);
        return {
          success: false,
          channel: 'email',
          recipient: payload.recipient,
          error: `Invalid email address: ${payload.recipient}`,
        };
      }

      // 2. Render template
      const template = renderTemplate(payload, this.config);

      // 3. Build rendered email
      const email: RenderedEmail = {
        from: this.config.from,
        replyTo: this.config.replyTo,
        to: resolvedRecipient,
        subject: template.subject,
        html: template.html,
        text: template.text,
        metadata: payload.metadata,
      };

      // 4. Send via transport
      const result = await this.transport.sendMail(email);

      // Track for backward-compatible getSentEmails()
      this.sentEmails.push(payload);

      this.logger.info(
        `Email delivered to ${resolvedRecipient} (messageId: ${result.messageId}, from: ${this.config.from})`,
      );

      return {
        success: true,
        channel: 'email',
        recipient: resolvedRecipient,
        deliveredAt: new Date(),
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown email error';
      this.logger.error(`Email delivery failed: ${message}`);

      return {
        success: false,
        channel: 'email',
        recipient: payload.recipient,
        error: message,
      };
    }
  }

  /**
   * Get all sent email payloads. Useful for testing.
   */
  getSentEmails(): NotificationPayload[] {
    return [...this.sentEmails];
  }

  /**
   * Get all rendered emails from the transport (if using InMemoryTransport).
   */
  getRenderedEmails(): RenderedEmail[] {
    if (this.transport instanceof InMemoryTransport) {
      return this.transport.getSentEmails();
    }
    return [];
  }

  /**
   * Clear sent emails. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
    if (this.transport instanceof InMemoryTransport) {
      this.transport.clearSentEmails();
    }
  }

  /**
   * Get the current configuration.
   */
  getConfig(): Readonly<EmailConfig> {
    return { ...this.config };
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  EmailAdapter,
  InMemoryTransport,
  resolveRecipient,
} from '../../src/adapters/email.adapter.js';
import type {
  RenderedEmail,
  EmailTransport,
} from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides: Partial<NotificationPayload> = {}): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    channel: 'email',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    metadata: { orderId: 'order-1', userId: 'user-1' },
    createdAt: new Date(),
    ...overrides,
  };
}

describe('resolveRecipient', () => {
  it('should accept valid email addresses', () => {
    expect(resolveRecipient('alice@example.com')).toBe('alice@example.com');
    expect(resolveRecipient('Bob@Example.COM')).toBe('bob@example.com');
    expect(resolveRecipient('user+tag@domain.co.uk')).toBe('user+tag@domain.co.uk');
  });

  it('should trim whitespace', () => {
    expect(resolveRecipient('  alice@example.com  ')).toBe('alice@example.com');
  });

  it('should reject invalid email addresses', () => {
    expect(resolveRecipient('')).toBeNull();
    expect(resolveRecipient('not-an-email')).toBeNull();
    expect(resolveRecipient('@missing-local.com')).toBeNull();
    expect(resolveRecipient('missing-domain@')).toBeNull();
    expect(resolveRecipient('has spaces@example.com')).toBeNull();
  });
});

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;
  let transport: InMemoryTransport;

  beforeEach(() => {
    transport = new InMemoryTransport();
    adapter = new EmailAdapter(
      { from: 'test@taskflowpro.com', appName: 'TaskFlow Pro', baseUrl: 'https://taskflowpro.com' },
      transport,
    );
  });

  it('should have channel set to email', () => {
    expect(adapter.channel).toBe('email');
  });

  describe('send', () => {
    it('should send order confirmation email with HTML template', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.channel).toBe('email');
      expect(result.recipient).toBe('alice@example.com');
      expect(result.deliveredAt).toBeInstanceOf(Date);

      const rendered = adapter.getRenderedEmails();
      expect(rendered).toHaveLength(1);
      expect(rendered[0]!.from).toBe('test@taskflowpro.com');
      expect(rendered[0]!.to).toBe('alice@example.com');
      expect(rendered[0]!.subject).toBe('Order Confirmation: order-1');
      expect(rendered[0]!.html).toContain('Order Confirmed');
      expect(rendered[0]!.html).toContain('order-1');
      expect(rendered[0]!.html).toContain('TaskFlow Pro');
    });

    it('should send order status update with status colors', async () => {
      const payload = makePayload({
        type: 'order_status_update',
        subject: 'Order Update: order-1',
        body: 'Your order status has changed from pending to shipped.',
        metadata: { orderId: 'order-1', previousStatus: 'pending', newStatus: 'shipped' },
      });

      const result = await adapter.send(payload);
      expect(result.success).toBe(true);

      const rendered = adapter.getRenderedEmails();
      expect(rendered[0]!.html).toContain('Order Status Update');
      expect(rendered[0]!.html).toContain('pending');
      expect(rendered[0]!.html).toContain('shipped');
      expect(rendered[0]!.html).toContain('#27AE60'); // shipped color
      expect(rendered[0]!.text).toContain('pending');
      expect(rendered[0]!.text).toContain('shipped');
    });

    it('should send welcome email with get-started link', async () => {
      const payload = makePayload({
        type: 'user_welcome',
        subject: 'Welcome to TaskFlow Pro!',
        body: 'Hi Alice, welcome to TaskFlow Pro. Your account has been created.',
        metadata: { userId: 'user-1' },
      });

      const result = await adapter.send(payload);
      expect(result.success).toBe(true);

      const rendered = adapter.getRenderedEmails();
      expect(rendered[0]!.html).toContain('Welcome to TaskFlow Pro');
      expect(rendered[0]!.html).toContain('Your Account is Ready');
      expect(rendered[0]!.html).toContain('https://taskflowpro.com/dashboard');
      expect(rendered[0]!.html).toContain('Get Started');
    });

    it('should render generic template for unknown notification types', async () => {
      const payload = makePayload({
        type: 'user_updated' as NotificationPayload['type'],
        subject: 'Profile Updated',
        body: 'Your profile has been updated.',
      });

      const result = await adapter.send(payload);
      expect(result.success).toBe(true);

      const rendered = adapter.getRenderedEmails();
      expect(rendered[0]!.html).toContain('Profile Updated');
      expect(rendered[0]!.html).toContain('Your profile has been updated.');
    });

    it('should normalize recipient email to lowercase', async () => {
      const payload = makePayload({ recipient: 'Alice@Example.COM' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.recipient).toBe('alice@example.com');

      const rendered = adapter.getRenderedEmails();
      expect(rendered[0]!.to).toBe('alice@example.com');
    });

    it('should fail for invalid recipient email', async () => {
      const payload = makePayload({ recipient: 'not-an-email' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid email address');
      expect(adapter.getSentEmails()).toHaveLength(0);
      expect(adapter.getRenderedEmails()).toHaveLength(0);
    });

    it('should track sent emails for backward compatibility', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const sent = adapter.getSentEmails();
      expect(sent).toHaveLength(1);
      expect(sent[0]!.recipient).toBe('alice@example.com');
    });

    it('should include replyTo when configured', async () => {
      const customAdapter = new EmailAdapter(
        { from: 'noreply@taskflowpro.com', replyTo: 'support@taskflowpro.com' },
        transport,
      );

      await customAdapter.send(makePayload());

      const rendered = transport.getSentEmails();
      expect(rendered[0]!.replyTo).toBe('support@taskflowpro.com');
    });

    it('should handle transport errors gracefully', async () => {
      const failingTransport: EmailTransport = {
        sendMail: async () => {
          throw new Error('SMTP connection refused');
        },
      };
      const failAdapter = new EmailAdapter({ from: 'test@example.com' }, failingTransport);

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('SMTP connection refused');
    });

    it('should escape HTML in template data', async () => {
      const payload = makePayload({
        body: 'Items: <script>alert("xss")</script>',
      });

      await adapter.send(payload);

      const rendered = adapter.getRenderedEmails();
      expect(rendered[0]!.html).not.toContain('<script>');
      expect(rendered[0]!.html).toContain('&lt;script&gt;');
    });

    it('should include metadata in rendered email', async () => {
      const payload = makePayload({
        metadata: { orderId: 'order-42', userId: 'user-7' },
      });

      await adapter.send(payload);

      const rendered = adapter.getRenderedEmails();
      expect(rendered[0]!.metadata).toEqual({ orderId: 'order-42', userId: 'user-7' });
    });
  });

  describe('clearSentEmails', () => {
    it('should clear both payload and rendered email stores', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentEmails()).toHaveLength(1);
      expect(adapter.getRenderedEmails()).toHaveLength(1);

      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
      expect(adapter.getRenderedEmails()).toHaveLength(0);
    });
  });

  describe('getConfig', () => {
    it('should return current configuration', () => {
      const config = adapter.getConfig();
      expect(config.from).toBe('test@taskflowpro.com');
      expect(config.appName).toBe('TaskFlow Pro');
    });

    it('should return a copy (not mutable reference)', () => {
      const config = adapter.getConfig();
      (config as Record<string, unknown>).from = 'hacked@evil.com';
      expect(adapter.getConfig().from).toBe('test@taskflowpro.com');
    });
  });

  describe('default configuration', () => {
    it('should use defaults when no config provided', () => {
      const defaultAdapter = new EmailAdapter();
      const config = defaultAdapter.getConfig();
      expect(config.from).toBe('noreply@taskflowpro.com');
      expect(config.appName).toBe('TaskFlow Pro');
      expect(config.baseUrl).toBe('https://taskflowpro.com');
    });
  });
});

describe('InMemoryTransport', () => {
  it('should store and retrieve sent emails', async () => {
    const transport = new InMemoryTransport();
    const email: RenderedEmail = {
      from: 'test@example.com',
      to: 'user@example.com',
      subject: 'Test',
      html: '<p>Hello</p>',
      text: 'Hello',
      metadata: {},
    };

    const result = await transport.sendMail(email);
    expect(result.messageId).toBeTruthy();
    expect(transport.getSentEmails()).toHaveLength(1);
    expect(transport.getSentEmails()[0]!.to).toBe('user@example.com');
  });

  it('should clear sent emails', async () => {
    const transport = new InMemoryTransport();
    await transport.sendMail({
      from: 'a@b.com', to: 'c@d.com', subject: 'X', html: '', text: '', metadata: {},
    });

    transport.clearSentEmails();
    expect(transport.getSentEmails()).toHaveLength(0);
  });
});

